# Structurizr DSL (C4モデル対応)
workspace {
  model {
    user = person "ユーザー"
    system = softwareSystem "決済システム" {
      webapp = container "Web App" "React" "HTTPS"
      api = container "API Server" "Node.js" "REST"
      db = container "Database" "PostgreSQL" "SQL"
    }
    user -> webapp "注文する"
    webapp -> api "REST API"
    api -> db "クエリ"
  }
  views {
    container system "ContainerView" {
      include *
      autoLayout lr
    }
  }
}
